def find_all_occurrences(arr, target):
    """
    Find all indices where target appears using binary search recursion

    Args:
        arr: Sorted list (may contain duplicates)
        target: Element to find

    Returns:
        List of all indices where target appears
    """
    def binary_search_left(arr, target, low, high):
        """Find first (leftmost) occurrence"""
        if low > high:
            return -1
        mid = low + (high - low) // 2
        if arr[mid] == target:
            # Check if this is truly the leftmost
            if mid == 0 or arr[mid - 1] < target:
                return mid
            return binary_search_left(arr, target, low, mid - 1)
        elif arr[mid] > target:
            return binary_search_left(arr, target, low, mid - 1)
        else:
            return binary_search_left(arr, target, mid + 1, high)

    def binary_search_right(arr, target, low, high):
        """Find last (rightmost) occurrence"""
        if low > high:
            return -1
        mid = low + (high - low) // 2
        if arr[mid] == target:
            # Check if this is truly the rightmost
            if mid == len(arr) - 1 or arr[mid + 1] > target:
                return mid
            return binary_search_right(arr, target, mid + 1, high)
        elif arr[mid] > target:
            return binary_search_right(arr, target, low, mid - 1)
        else:
            return binary_search_right(arr, target, mid + 1, high)

    # Find leftmost and rightmost positions
    left = binary_search_left(arr, target, 0, len(arr) - 1)
    if left == -1:
        return []
    right = binary_search_right(arr, target, 0, len(arr) - 1)

    # Return all indices in range
    return list(range(left, right + 1))


# Test the function - sorted array with duplicates
sorted_with_duplicates = [5, 10, 10, 10, 15, 20, 20, 25]
target = 10

result = find_all_occurrences(sorted_with_duplicates, target)
print(f"Target {target} found at indices: {result}")
print(f"Total occurrences: {len(result)}")
